const data = $input.first().json;
return {
  json: {
    customer_name: data.customer_name || '',
    customer_email: data.customer_email || '',
    customer_phone: data.customer_phone || '',
    service: data.service || '',
    amount: data.amount || null,
    plan_name: data.service || 'lawn-care'
  }
};

const leads = $('Get Lead').first().json;
const plans = $('Get Plans').first().json;
const extracted = $('Extract Data').first().json;

const leadArr = Array.isArray(leads) ? leads : [leads];
const planArr = Array.isArray(plans) ? plans : [plans];

const lead = leadArr[0] || {};
const serviceLower = (extracted.plan_name || '').toLowerCase();

let matchedPlan = planArr.find(p => p.name && p.name.toLowerCase().includes(serviceLower));
if (!matchedPlan) matchedPlan = planArr[0] || {};

const startDate = new Date();
const endDate = new Date();
endDate.setMonth(endDate.getMonth() + (matchedPlan.duration_months || 12));

return {
  json: {
    lead_id: lead.id || null,
    plan_id: matchedPlan.id || null,
    plan_name: matchedPlan.name || 'Standard Plan',
    price: matchedPlan.price_monthly || extracted.amount,
    start_date: startDate.toISOString().split('T')[0],
    end_date: endDate.toISOString().split('T')[0],
    customer_name: extracted.customer_name,
    customer_phone: extracted.customer_phone,
    customer_email: extracted.customer_email
  }
};

